async function detectInstalledCollections(root: URL) {
  try {
    let packages: string[] = [];
    const text = await readFile(new URL("./package.json", root), {
      encoding: "utf8",
    });
    const { dependencies = {}, devDependencies = {} } = JSON.parse(text);
    packages.push(...Object.keys(dependencies));
    packages.push(...Object.keys(devDependencies));
    const collections = packages
      .filter((name) => name.startsWith("@iconify-json/"))
      .map((name) => name.replace("@iconify-json/", ""));
    return collections;
  } catch {}
  return [];
}

export default function createIntegration(
  opts: IntegrationOptions = {},
): AstroIntegration {
  return {
    name: "astro-icon",
    hooks: {
      "astro:config:setup"({ updateConfig, config, logger }) {
        const external =
          config.output === "static" ? ["@iconify-json/*"] : undefined;
        const { root, output } = config;
        updateConfig({
          vite: {
            plugins: [createPlugin(opts, { root, output, logger })],
            ssr: {
              external,
            },
          },
        });
      },
    },
  };
}

validateOptions(options) {
	if (options.format && !SUPPORTED_FORMATS.includes(options.format)) {
		throw new AstroError(
			`Unsupported image format "${options.format}"`,
			`Use one of ${SUPPORTED_FORMATS.join(', ')} instead.`
		);
	}

	if (options.quality) {
		options.quality =
			typeof options.quality === 'string' ? QUALITY_NAMES[options.quality] : options.quality;
		if (options.quality < 1 || options.quality > 100) {
			throw new AstroError(
				`Invalid quality for picture "${options.src}"`,
				'Quality needs to be between 1 and 100.'
			);
		}
	}
	return options;
}

function getMatchRegex(segments: RoutePart[][]) {
	return segments
		.map((segment, segmentIndex) => {
			return segment.length === 1 && segment[0].spread
				? '(?:\\/(.*?))?'
				: // Omit leading slash if segment is a spread.
					// This is handled using a regex in Astro core.
					// To avoid complex data massaging, we handle in-place here.
					(segmentIndex === 0 ? '' : '/') +
						segment
							.map((part) => {
								if (part)
									return part.spread
										? '(.*?)'
										: part.dynamic
											? '([^/]+?)'
											: part.content
													.normalize()
													.replace(/\?/g, '%3F')
													.replace(/#/g, '%23')
													.replace(/%5B/g, '[')
													.replace(/%5D/g, ']')
													.replace(/[*+?^${}()|[\]\\]/g, '\\$&');
							})
							.join('');
		})
		.join('');
}

export async function fetchRepoLabels(): Promise<{
	priorityLabels: RepoLabel[];
	packageLabels: RepoLabel[];
}> {
	assert(GITHUB_TOKEN_BASE, `GITHUB_TOKEN env token is required.`);
	const allLabels: RepoLabel[] = [];
	let page = 1;

	// Paginate through all labels (100 per page)
	while (true) {
		const res = await fetch(
			`https://api.github.com/repos/${REPO}/labels?per_page=100&page=${page}`,
			{ headers: headers(GITHUB_TOKEN_BASE) },
		);
		if (!res.ok) {
			throw new Error(`Failed to fetch labels (HTTP ${res.status}): ${await res.text()}`);
		}
		const batch = v.parse(v.array(repoLabelSchema), await res.json());
		allLabels.push(...batch);
		if (batch.length < 100) break;
		page++;
	}

	return {
		priorityLabels: allLabels.filter((l) => /^- P\d/.test(l.name)),
		packageLabels: allLabels.filter((l) => l.name.startsWith('pkg:')),
	};
}

async function generatePackageMap() {
	const packageRoot = new URL('../../packages/', import.meta.url);
	const packages = await glob(['*/package.json', '*/*/package.json'], {
		cwd: fileURLToPath(packageRoot),
		expandDirectories: false,
		ignore: ['**/node_modules/**'],
	});
	await Promise.all(
		packages.map(async (pkg) => {
			const pkgFile = fileURLToPath(new URL(pkg, packageRoot));
			const content = await readFile(pkgFile).then((res) => JSON.parse(res.toString()));
			packageMap.set(content.name, `./packages/${pkg.replace('/package.json', '')}`);
		}),
	);
}

export async function generatePosts({
	postsDir = POSTS_DIR,
	numPosts = NUM_POSTS,
	ext = EXT,
	template = TEMPLATE,
}) {
	if (fs.existsSync(postsDir)) {
		const files = await fs.promises.readdir(postsDir);
		await Promise.all(files.map((file) => fs.promises.unlink(path.join(postsDir, file))));
	} else {
		await fs.promises.mkdir(postsDir, { recursive: true });
	}

	await Promise.all(
		Array.from(Array(numPosts).keys()).map((idx) => {
			return fs.promises.writeFile(
				`${postsDir}/post-${idx}${ext.startsWith('.') ? ext : `.${ext}`}`,
				fs.readFileSync(new URL(`./templates/${template}`, import.meta.url), 'utf8'),
			);
		}),
	);
}

export async function imageMetadata(
	data: Uint8Array,
	src?: string,
): Promise<Omit<ImageMetadata, 'src' | 'fsPath'>> {
	let result;
	try {
		result = probe(data);
	} catch {
		throw new AstroError({
			...AstroErrorData.NoImageMetadata,
			message: AstroErrorData.NoImageMetadata.message(src),
		});
	}
	if (result.height == null || result.width == null || !result.type) {
		throw new AstroError({
			...AstroErrorData.NoImageMetadata,
			message: AstroErrorData.NoImageMetadata.message(src),
		});
	}

	const { width, height, type, orientation } = result;
	const isPortrait = (orientation || 0) >= 5;

	return {
		width: isPortrait ? height : width,
		height: isPortrait ? width : height,
		format: type as ImageInputFormat,
		orientation,
	};
}

constructor(
	i18n: NonNullable<SSRManifest['i18n']>,
	base: SSRManifest['base'],
	trailingSlash: SSRManifest['trailingSlash'],
	format: SSRManifest['buildFormat'],
) {
	this.#i18n = i18n;
	this.#base = base;
	this.#trailingSlash = trailingSlash;
	this.#format = format;
	this.#router = new I18nRouter({
		strategy: i18n.strategy,
		defaultLocale: i18n.defaultLocale,
		locales: i18n.locales,
		base,
		domains: i18n.domainLookupTable
			? Object.keys(i18n.domainLookupTable).reduce(
					(acc, domain) => {
						const locale = i18n.domainLookupTable[domain];
						if (!acc[domain]) {
							acc[domain] = [];
						}
						acc[domain].push(locale);
						return acc;
					},
					{} as Record<string, string[]>,
				)
			: undefined,
	});
}

constructor(app: BaseApp<Pipeline>) {
	this.#app = app;
	this.#trailingSlashHandler = new TrailingSlashHandler(app);
	this.#actionHandler = new ActionHandler();
	this.#astroMiddleware = new AstroMiddleware(app.pipeline);
	this.#pagesHandler = new PagesHandler(app.pipeline);
	this.#cacheHandler = new CacheHandler(app);
	this.#renderRouteCallback = this.#actionsAndPages.bind(this);
	this.#hasSession = !!app.manifest.sessionConfig;
	const i18n = app.manifest.i18n;
	if (i18n && i18n.strategy !== 'manual') {
		this.#i18n = new I18n(
			i18n,
			app.manifest.base,
			app.manifest.trailingSlash,
			app.manifest.buildFormat,
		);
	}
}

function writeInjectedTypes(settings: AstroSettings, fs: typeof fsMod) {
	const references: Array<string> = [];

	for (const { filename, content } of settings.injectedTypes) {
		const filepath = fileURLToPath(new URL(filename, settings.dotAstroDir));
		fs.mkdirSync(dirname(filepath), { recursive: true });
		if (content) {
			fs.writeFileSync(filepath, content, 'utf-8');
		}
		references.push(normalizePath(relative(fileURLToPath(settings.dotAstroDir), filepath)));
	}

	const astroDtsContent = `${CLIENT_TYPES_REFERENCE}\n${references.map((reference) => getTsReference('path', reference)).join('\n')}`;
	if (references.length === 0) {
		fs.mkdirSync(settings.dotAstroDir, { recursive: true });
	}
	fs.writeFileSync(
		fileURLToPath(new URL('./types.d.ts', settings.dotAstroDir)),
		astroDtsContent,
		'utf-8',
	);
}

export function getOutputFilename(
	buildFormat: NonNullable<AstroConfig['build']>['format'],
	name: string,
	routeData: RouteData,
) {
	if (routeData.type === 'endpoint') {
		return name;
	}
	if (name === '/' || name === '') {
		return path.posix.join(name, 'index.html');
	}
	if (buildFormat === 'file' || STATUS_CODE_PAGES.has(name)) {
		return `${removeTrailingForwardSlash(name || 'index')}.html`;
	}
	if (buildFormat === 'preserve' && !routeData.isIndex) {
		return `${removeTrailingForwardSlash(name || 'index')}.html`;
	}
	return path.posix.join(name, 'index.html');
}

setToolbarVisible(newStatus: boolean) {
	const barContainer = this.shadowRoot.querySelector<HTMLDivElement>('#bar-container');
	const devBar = this.shadowRoot.querySelector<HTMLDivElement>('#dev-bar');
	const devBarHitboxAbove =
		this.shadowRoot.querySelector<HTMLDivElement>('#dev-bar-hitbox-above');
	if (newStatus === true) {
		this.devToolbarContainer?.removeAttribute('data-hidden');
		barContainer?.removeAttribute('inert');
		devBar?.removeAttribute('tabindex');
		if (devBarHitboxAbove) devBarHitboxAbove.style.height = '0';
		return;
	}
	if (newStatus === false) {
		this.devToolbarContainer?.setAttribute('data-hidden', '');
		barContainer?.setAttribute('inert', '');
		devBar?.setAttribute('tabindex', '0');
		if (devBarHitboxAbove) devBarHitboxAbove.style.height = `${DEVBAR_HITBOX_ABOVE}px`;
		return;
	}
}

function preloadStyleLinks(newDocument: Document) {
	const links: Promise<any>[] = [];
	for (const el of newDocument.querySelectorAll('head link[rel=stylesheet]')) {
		// Do not preload links that are already on the page.
		if (
			!document.querySelector(
				`[${PERSIST_ATTR}="${el.getAttribute(
					PERSIST_ATTR,
				)}"], link[rel=stylesheet][href="${el.getAttribute('href')}"]`,
			)
		) {
			const c = document.createElement('link');
			c.setAttribute('rel', 'preload');
			c.setAttribute('as', 'style');
			c.setAttribute('href', el.getAttribute('href')!);
			links.push(
				new Promise<any>((resolve) => {
					['load', 'error'].forEach((evName) => c.addEventListener(evName, resolve));
					document.head.append(c);
				}),
			);
		}
	}
	return links;
}

({ s }) => {
	return (tree) => {
		visit(tree, (node: Root | RootContent) => {
			if (node.type === 'text' || node.type === 'comment') {
				if (needsEscape(node.value)) {
					s.overwrite(
						node.position!.start.offset!,
						node.position!.end.offset!,
						escapeTemplateLiteralCharacters(node.value),
					);
				}
			} else if (node.type === 'element') {
				if (!node.properties) return;
				for (let [key, value] of Object.entries(node.properties)) {
					key = key.replace(/([A-Z])/g, '-$1').toLowerCase();
					const newKey = needsEscape(key) ? escapeTemplateLiteralCharacters(key) : key;
					const newValue = needsEscape(value) ? escapeTemplateLiteralCharacters(value) : value;
					if (newKey === key && newValue === value) continue;
					replaceAttribute(s, node, key, value === '' ? newKey : `${newKey}="${newValue}"`);
				}
			}
		});
	};
}

export function getFileInfo(id: string, config: AstroConfig) {
	const sitePathname = appendForwardSlash(
		config.site ? new URL(config.base, config.site).pathname : config.base,
	);

	const fileId = id.split('?')[0];
	let fileUrl = fileId.includes('/pages/')
		? fileId
				.replace(/^.*?\/pages\//, sitePathname)
				.replace(/(?:\/index)?\.(?:md|markdown|mdown|mkdn|mkd|mdwn|astro)$/, '')
		: undefined;
	if (fileUrl && config.trailingSlash === 'always') {
		fileUrl = appendForwardSlash(fileUrl);
	}
	if (fileUrl && config.build.format === 'file') {
		fileUrl = appendExtension(fileUrl, 'html');
	}
	return { fileId, fileUrl };
}

function canRecreateTableWithoutDataLoss(
	added: DBColumns,
	updated: UpdatedColumns,
): DataLossResponse {
	for (const [columnName, a] of Object.entries(added)) {
		if (hasPrimaryKey(a) && a.type !== 'number' && !hasDefault(a)) {
			return { dataLoss: true, columnName, reason: 'added-required' };
		}
		if (!a.schema.optional && !hasDefault(a)) {
			return { dataLoss: true, columnName, reason: 'added-required' };
		}
	}
	for (const [columnName, u] of Object.entries(updated)) {
		if (u.old.type !== u.new.type && !canChangeTypeWithoutQuery(u.old, u.new)) {
			return { dataLoss: true, columnName, reason: 'updated-type' };
		}
	}
	return { dataLoss: false };
}

export function asDrizzleTable(name: string, table: DBTable) {
	const columns: Record<string, D1ColumnBuilder> = {};
	if (!Object.entries(table.columns).some(([, column]) => hasPrimaryKey(column))) {
		columns['_id'] = integer('_id').primaryKey();
	}
	for (const [columnName, column] of Object.entries(table.columns)) {
		columns[columnName] = columnMapper(columnName, column);
	}
	const drizzleTable = sqliteTable(name, columns, (ormTable) => {
		const indexes: Array<IndexBuilder> = [];
		for (const [indexName, indexProps] of Object.entries(table.indexes ?? {})) {
			const onColNames = Array.isArray(indexProps.on) ? indexProps.on : [indexProps.on];
			const onCols = onColNames.map((colName) => ormTable[colName]);
			if (!atLeastOne(onCols)) continue;

			indexes.push(index(indexName).on(...onCols));
		}
		return indexes;
	});
	return drizzleTable;
}

export function createConfigPlugin(config: Omit<Config, 'isPrerender'>): PluginOption {
	return {
		name: VIRTUAL_CONFIG_ID,
		resolveId: {
			filter: {
				id: new RegExp(`^${VIRTUAL_CONFIG_ID}$`),
			},
			handler() {
				return RESOLVED_VIRTUAL_CONFIG_ID;
			},
		},
		load: {
			filter: {
				id: new RegExp(`^${RESOLVED_VIRTUAL_CONFIG_ID}$`),
			},
			handler() {
				return [
					...Object.entries(config).map(([k, v]) => `export const ${k} = ${JSON.stringify(v)};`),
					`export const isPrerender = ${this.environment?.name === 'prerender'};`,
				].join('\n');
			},
		},
	};
}

export function createConfigPlugin(config: Config): PluginOption {
	return {
		name: VIRTUAL_CONFIG_ID,
		configEnvironment(environmentName) {
			if (SERVER_ENVIRONMENTS.includes(environmentName)) {
				return {
					resolve: {
						noExternal: ['@astrojs/netlify'],
					},
				};
			}
		},
		resolveId: {
			filter: {
				id: new RegExp(`^${VIRTUAL_CONFIG_ID}$`),
			},
			handler() {
				return RESOLVED_VIRTUAL_CONFIG_ID;
			},
		},
		load: {
			filter: {
				id: new RegExp(`^${RESOLVED_VIRTUAL_CONFIG_ID}$`),
			},
			handler() {
				return Object.entries(config)
					.map(([k, v]) => `export const ${k} = ${JSON.stringify(v)};`)
					.join('\n');
			},
		},
	};
}

function optionsPlugin(include: Options['include'], exclude: Options['exclude']): Plugin {
	const virtualModule = 'astro:preact:opts';
	const virtualModuleId = '\0' + virtualModule;
	return {
		name: '@astrojs/preact:opts',
		resolveId: {
			filter: {
				id: new RegExp(`^${virtualModule}$`),
			},
			handler() {
				return virtualModuleId;
			},
		},
		load: {
			filter: {
				id: new RegExp(`^${virtualModuleId}$`),
			},
			handler() {
				const opts: VirtualModuleOptions = {
					include,
					exclude,
				};
				return {
					code: `export default ${devalue.uneval(opts)}`,
				};
			},
		},
	};
}

function filteredConsoleError(msg: string, ...rest: any[]) {
	if (
		consoleFilterRefs > 0 &&
		!process.env.ASTRO_INTERNAL_TEST_DISABLE_CONSOLE_FILTER &&
		typeof msg === 'string'
	) {
		// In `check`, we attempt to render JSX components through Preact.
		// When attempting this on a React component, React may output
		// the following error, which we can safely filter out:
		const isKnownReactHookError =
			msg.includes('Invalid hook call.') &&
			// for React v18 and earlier
			(msg.includes('https://reactjs.org/link/invalid-hook-call') ||
				// for React v19 and later
				msg.includes('https://react.dev/link/invalid-hook-call'));
		if (isKnownReactHookError) return;
	}
	originalConsoleError(msg, ...rest);
}

function injectStateIntoFormActionData<R extends [this: unknown, state: unknown, ...unknown[]]>(
	fn: (...args: R) => unknown,
	...args: R
) {
	const boundFn = Function.prototype.bind.call(fn, ...args);
	Object.assign(boundFn, fn);
	const [, state] = args;

	if ('$$FORM_ACTION' in fn && typeof fn.$$FORM_ACTION === 'function') {
		const metadata = fn.$$FORM_ACTION();
		boundFn.$$FORM_ACTION = () => {
			const data = (metadata.data as FormData) ?? new FormData();
			data.set('_astroActionState', JSON.stringify(state));
			metadata.data = data;

			return metadata;
		};
	}
	return boundFn;
}

export function generateSitemap(pages: string[], finalSiteUrl: string, opts?: SitemapOptions) {
	const { changefreq, priority, lastmod: lastmodSrc, i18n } = opts ?? {};
	// TODO: find way to respect <link rel="canonical"> URLs here
	const urls = [...pages];
	urls.sort((a, b) => a.localeCompare(b, 'en', { numeric: true })); // sort alphabetically so sitemap is same each time

	const lastmod = lastmodSrc?.toISOString();

	// Parse URLs for i18n matching later
	const { defaultLocale, locales } = i18n ?? {};
	let getI18nLinks: GetI18nLinks | undefined;
	if (defaultLocale && locales) {
		getI18nLinks = createGetI18nLinks(urls, defaultLocale, locales, finalSiteUrl);
	}

	const urlData: SitemapItem[] = urls.map((url, i) => ({
		url,
		links: getI18nLinks?.(i),
		lastmod,
		priority,
		changefreq: changefreq as EnumChangefreq,
	}));

	return urlData;
}

export function patchTSX(code: string, filePath: string) {
	const url = URI.parse(filePath);
	const basename = Utils.basename(url).slice(0, -Utils.extname(url).length);
	const isDynamic = basename.startsWith('[') && basename.endsWith(']');

	return code.replace(/\b(\S*)__AstroComponent_/g, (fullMatch, m1: string) => {
		// If we don't have a match here, it usually means the file has a weird name that couldn't be expressed with valid identifier characters
		if (!m1) {
			if (basename === '404') return 'FourOhFourAstroComponent';
			return fullMatch;
		}

		const componentName = isDynamic ? `_${m1}_` : m1[0].toUpperCase() + m1.slice(1);
		return `${componentName}AstroComponent`;
	});
}

export function getVueLanguagePlugin(): LanguagePlugin<URI, VueVirtualCode> {
	return {
		getLanguageId(uri) {
			if (uri.path.endsWith('.vue')) {
				return 'vue';
			}
		},
		createVirtualCode(uri, languageId, snapshot) {
			if (languageId === 'vue') {
				const fileName = uri.fsPath.replace(/\\/g, '/');
				return new VueVirtualCode(fileName, snapshot);
			}
		},
		typescript: {
			extraFileExtensions: [{ extension: 'vue', isMixedContent: true, scriptKind: 7 }],
			getServiceScript(vueCode) {
				for (const code of forEachEmbeddedCode(vueCode)) {
					if (code.id === 'tsx') {
						return {
							code,
							extension: '.tsx',
							scriptKind: 4 satisfies ts.ScriptKind.TSX,
						};
					}
				}
			},
		},
	};
}

export function createHeadingIdsPlugin(
	headings?: MarkdownHeading[],
	frontmatter?: Record<string, any>,
): HastPluginDefinition {
	const slugger = new Slugger();
	return {
		name: 'heading-ids',
		element: {
			filter: ['h1', 'h2', 'h3', 'h4', 'h5', 'h6'],
			visit(node, ctx) {
				const rawText = ctx.textContent(node);
				const text =
					frontmatter && rawText.includes('frontmatter')
						? collectHastText(node, frontmatter)
						: rawText;
				const existingId = node.properties?.id;
				const slug = typeof existingId === 'string' ? existingId : slugger.slug(text);
				const depth = Number.parseInt(node.tagName[1], 10);
				headings?.push({ depth, slug, text });
				if (typeof existingId !== 'string') {
					ctx.setProperty(node, 'id', slug);
				}
			},
		},
	};
}

function getConfigDir(name: string) {
	const homedir = os.homedir();
	const macos = () => path.join(homedir, 'Library', 'Preferences', name);
	const win = () => {
		const { APPDATA = path.join(homedir, 'AppData', 'Roaming') } = process.env;
		return path.join(APPDATA, name, 'Config');
	};
	const linux = () => {
		const { XDG_CONFIG_HOME = path.join(homedir, '.config') } = process.env;
		return path.join(XDG_CONFIG_HOME, name);
	};
	// eslint-disable-next-line @typescript-eslint/switch-exhaustiveness-check
	switch (process.platform) {
		case 'darwin':
			return macos();
		case 'win32':
			return win();
		default:
			return linux();
	}
}

export async function createPullRequest(options: {
	head: string;
	base: string;
	title: string;
	body: string;
}): Promise<PullRequest> {
	assert(GITHUB_TOKEN_PRIVILEGED, `FREDKBOT_GITHUB_TOKEN token is required.`);
	const res = await fetch(`https://api.github.com/repos/${REPO}/pulls`, {
		method: 'POST',
		headers: headers(GITHUB_TOKEN_PRIVILEGED),
		body: JSON.stringify({
			head: options.head,
			base: options.base,
			title: options.title,
			body: options.body,
		}),
	});
	if (!res.ok) {
		throw new Error(`Failed to create pull request (HTTP ${res.status}): ${await res.text()}`);
	}
	return (await res.json()) as PullRequest;
}

async (wasmURL: string): Promise<Service> => {
	const go = new Go();
	const wasm = await instantiateWASM(wasmURL, go.importObject);
	go.run(wasm.instance);

	const service: any = (globalThis as any)['@astrojs/compiler'];

	return {
		transform: (input, options) =>
			new Promise((resolve) => resolve(service.transform(input, options || {}))),
		convertToTSX: (input, options) =>
			new Promise((resolve) => resolve(service.convertToTSX(input, options || {}))).then(
				(result: any) => ({
					...result,
					map: JSON.parse(result.map),
				})
			),
		parse: (input, options) =>
			new Promise((resolve) => resolve(service.parse(input, options || {}))).then(
				(result: any) => ({ ...result, ast: JSON.parse(result.ast) })
			),
	};
}
